#include <stdio.h>
#include <stdlib.h>

#define FRAME_COUNT 4
#define PAGE_COUNT 8

typedef struct {
    int frame_number;
    int valid;
    int dirty;
} PageTableEntry;

PageTableEntry pageTable[PAGE_COUNT];
int frames[FRAME_COUNT];
int pageFaults = 0;

void initPageTable() {
    for (int i = 0; i < PAGE_COUNT; i++) {
        pageTable[i].valid = 0;
        pageTable[i].dirty = 0;
    }
    for (int i = 0; i < FRAME_COUNT; i++) {
        frames[i] = -1;  // Empty frame
    }
}

int findFreeFrame() {
    for (int i = 0; i < FRAME_COUNT; i++) {
        if (frames[i] == -1) return i;
    }
    return -1;  // No free frame
}

int getPageFromDisk(int page) {
    printf("  -> Loading page %d from disk...\n", page);
    return 1;  // Simulate disk I/O
}

void accessPage(int pageNumber) {
    printf("Accessing virtual page %d...\n", pageNumber);

    if (!pageTable[pageNumber].valid) {
        // Page fault
        pageFaults++;
        printf("  PAGE FAULT!\n");

        int frame = findFreeFrame();
        if (frame == -1) {
            // Need replacement - use simple FIFO
            static int nextEvict = 0;
            frame = nextEvict;
            nextEvict = (nextEvict + 1) % FRAME_COUNT;

            // Write back if dirty
            for (int i = 0; i < PAGE_COUNT; i++) {
                if (pageTable[i].valid && pageTable[i].frame_number == frame) {
                    if (pageTable[i].dirty) {
                        printf("  Writing dirty page %d to disk\n", i);
                    }
                    pageTable[i].valid = 0;
                    break;
                }
            }
        }

        getPageFromDisk(pageNumber);
        pageTable[pageNumber].valid = 1;
        pageTable[pageNumber].frame_number = frame;
        pageTable[pageNumber].dirty = 0;
        frames[frame] = pageNumber;
    } else {
        printf("  Page found in frame %d\n", pageTable[pageNumber].frame_number);
    }
}

int main() {
    initPageTable();

    int referenceString[] = {1, 2, 3, 4, 1, 2, 5, 1, 2, 3, 4, 5};
    int refLength = sizeof(referenceString) / sizeof(referenceString[0]);

    printf("=== Demand Paging Simulation ===\n\n");

    for (int i = 0; i < refLength; i++) {
        accessPage(referenceString[i]);
    }

    printf("\nTotal Page Faults: %d\n", pageFaults);

    return 0;
}
